/* jshint esversion: 6, expr: true, -W033 */ document.addEventListener("DOMContentLoaded",(function(){const e=document.querySelectorAll(".-scroll");window.addEventListener("scroll",(()=>{e.forEach((e=>{((e,t=1)=>e.getBoundingClientRect().top<=(window.innerHeight||document.documentElement.clientHeight)/t)(e,1.05)?e.classList.add("scrolled"):(e=>e.getBoundingClientRect().top>(window.innerHeight||document.documentElement.clientHeight))(e)&&e.classList.remove("scrolled")}))}))}));